import sys

def is_tak_code(grid, i, j):
    # Check top-left 3x3 region
    for row in range(3):
        for col in range(3):
            if grid[i + row][j + col] != '#':
                return False

    # Check bottom-right 3x3 region
    for row in range(3):
        for col in range(3):
            if grid[i + row + 6][j + col + 6] != '#':
                return False

    # Check adjacent cells around top-left 3x3
    for row in range(3):
        for col in range(3):
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    r = i + row + dr
                    c = j + col + dc
                    if 0 <= r < 9 and 0 <= c < 9:
                        if (r < 3 or c < 3) and grid[r][c] != '#':
                            return False
                        if (r >= 6 or c >= 6) and grid[r][c] != '#':
                            return False
                        if (r < 3 and c >= 3) or (r >= 6 and c < 6):
                            if grid[r][c] != '.':
                                return False

    # Check adjacent cells around bottom-right 3x3
    for row in range(3):
        for col in range(3):
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    r = i + row + dr + 6
                    c = j + col + dc + 6
                    if 0 <= r < 9 and 0 <= c < 9:
                        if (r < 3 or c < 3) and grid[r][c] != '#':
                            return False
                        if (r >= 6 or c >= 6) and grid[r][c] != '#':
                            return False
                        if (r < 3 and c >= 3) or (r >= 6 and c < 6):
                            if grid[r][c] != '.':
                                return False

    return True

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    M = int(input[1])
    grid = input[2:N+2]

    result = []
    for i in range(N - 8):
        for j in range(M - 8):
            if is_tak_code(grid, i, j):
                result.append(f"{i + 1} {j + 1}")

    for line in result:
        print(line)

if __name__ == "__main__":
    main()
